proof fn phi_1_entails_apply_closure_bridge(ex: Execution<int>, p: TempPred<int>, q: TempPred<int>)
    requires
        p.entails(q),
        p.satisfied_by(ex),
    ensures
        q.satisfied_by(ex),
{
    entails_apply::<int>(ex, p, q);
}

proof fn phi_2_use_tla_forall_instantiation(spec: TempPred<int>, a_to_p: spec_fn(int) -> TempPred<int>, a: int)
    requires
        spec.entails(tla_forall(a_to_p)),
    ensures
        spec.entails(a_to_p(a)),
{
    use_tla_forall::<int, int>(spec, a_to_p, a);
}

proof fn phi_3_entails_transitive_via_apply(p: TempPred<int>, q: TempPred<int>, r: TempPred<int>)
    requires
        p.entails(q),
        q.entails(r),
    ensures
        p.entails(r),
{
    assert forall |ex: Execution<int>| #[trigger] p.satisfied_by(ex) implies r.satisfied_by(ex) by {
        entails_apply::<int>(ex, p, q);
        entails_apply::<int>(ex, q, r);
    };
}

proof fn phi_4_tla_forall_vacuous_any_pred(spec: TempPred<int>, a_to_p: spec_fn(int) -> TempPred<int>, a: int, ex: Execution<int>)
    requires
        spec.entails(tla_forall(a_to_p)),
        spec.satisfied_by(ex),
    ensures
        a_to_p(a).satisfied_by(ex),
{
    entails_apply::<int>(ex, spec, tla_forall(a_to_p));
}

proof fn phi_5_entails_apply_self_implies(p: TempPred<int>, q: TempPred<int>, ex: Execution<int>)
    requires
        valid(p.implies(q)),
        p.satisfied_by(ex),
    ensures
        q.satisfied_by(ex),
{
    entails_apply::<int>(ex, p, q);
}
